// Solution
function validateRouteParameter(req, res, next) {
  const id = parseInt(req.params.id);
  if (isNaN(id) || id <= 0) {
    res.status(400).send('Invalid route parameter');
  } else {
    next();
  }
}
module.exports = validateRouteParameter;

solutions.python:
def validateRouteParameter(req, res, next):
    try:
        id = int(req.params.id)
        if id <= 0:
            res.status(400).send('Invalid route parameter')
        else:
            next()
    except ValueError:
        res.status(400).send('Invalid route parameter')
